<?php
namespace App\Services;use App\Exceptions\FriendlyException;use App\Models\Wallet;use App\Models\WalletTransaction;use Illuminate\Support\Facades\DB;class WalletService{public function ensure(int $userId,string $currency='INR'):Wallet{return Wallet::firstOrCreate(['user_id'=>$userId],['balance_minor'=>0,'currency_code'=>$currency]);}public function credit(int $userId,int $amountMinor,string $note,string $refType,string $refId):WalletTransaction{return DB::transaction(function()use($userId,$amountMinor,$note,$refType,$refId){$wallet=$this->ensure($userId);$wallet=Wallet::whereKey($wallet->id)->lockForUpdate()->firstOrFail();$before=$wallet->balance_minor;$after=$before+$amountMinor;$wallet->update(['balance_minor'=>$after]);return WalletTransaction::create(['user_id'=>$userId,'wallet_id'=>$wallet->id,'type'=>'credit','amount_minor'=>$amountMinor,'balance_before_minor'=>$before,'balance_after_minor'=>$after,'currency_code'=>$wallet->currency_code,'note'=>$note,'reference_type'=>$refType,'reference_id'=>$refId,'idempotency_key'=>$refType.'-'.$refId.'-credit']);},5);}public function debit(int $userId,int $amountMinor,string $note,string $refType,string $refId):WalletTransaction{return DB::transaction(function()use($userId,$amountMinor,$note,$refType,$refId){$wallet=Wallet::where('user_id',$userId)->lockForUpdate()->first();if(!$wallet){$wallet=Wallet::create(['user_id'=>$userId,'balance_minor'=>0,'currency_code'=>'INR']);}if($wallet->balance_minor<$amountMinor){throw new FriendlyException('Insufficient wallet balance. Please recharge wallet or use online payment.');}$before=$wallet->balance_minor;$after=$before-$amountMinor;$wallet->update(['balance_minor'=>$after]);return WalletTransaction::create(['user_id'=>$userId,'wallet_id'=>$wallet->id,'type'=>'debit','amount_minor'=>$amountMinor,'balance_before_minor'=>$before,'balance_after_minor'=>$after,'currency_code'=>$wallet->currency_code,'note'=>$note,'reference_type'=>$refType,'reference_id'=>$refId,'idempotency_key'=>$refType.'-'.$refId.'-debit']);},5);}}
